const QUESTION_BANK_UPLOAD_OPTION_TYPES = new Set(['multipleChoice', 'preference', 'sortIntoOrder']);
const normalizeQuestionBankUploadHeader = (value) =>
  String(value || '').trim().toLowerCase().replace(/[^a-z0-9]/g, '');
const parseQuestionBankUploadHeaderRow = (rawText = '') => {
  const text = String(rawText || '').replace(/^\uFEFF/, '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  const cells = [];
  let field = '';
  let inQuotes = false;

  for (let index = 0; index < text.length; index += 1) {
    const char = text[index];
    const next = text[index + 1];
    if (char === '"' && inQuotes && next === '"') {
      field += '"';
      index += 1;
    } else if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      cells.push(field.trim());
      field = '';
    } else if (char === '\n' && !inQuotes) {
      cells.push(field.trim());
      return cells;
    } else {
      field += char;
    }
  }

  cells.push(field.trim());
  return cells.filter(Boolean);
};
const validateQuestionBankUploadHeaders = (rawText = '') => {
  const headers = parseQuestionBankUploadHeaderRow(rawText);
  const headerKeys = new Set(headers.map(normalizeQuestionBankUploadHeader).filter(Boolean));
  const missingColumns = QUESTION_BANK_UPLOAD_COLUMNS.filter(
    (column) => !headerKeys.has(normalizeQuestionBankUploadHeader(column)),
  );
  if (missingColumns.length) {
    const firstMissing = missingColumns.slice(0, 8).join(', ');
    throw new Error(
      `CSV is missing required template columns: ${firstMissing}${missingColumns.length > 8 ? '...' : ''}. Download the blank template first.`,
    );
  }
};
const parseQuestionBankUploadCsvRows = (rawText = '') => {
  const rows = [];
  let row = [];
  let field = '';
  let inQuotes = false;
  const text = String(rawText || '').replace(/^\uFEFF/, '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');

  for (let index = 0; index < text.length; index += 1) {
    const char = text[index];
    const next = text[index + 1];
    if (char === '"' && inQuotes && next === '"') {
      field += '"';
      index += 1;
    } else if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      row.push(field.trim());
      field = '';
    } else if (char === '\n' && !inQuotes) {
      row.push(field.trim());
      if (row.some(Boolean)) rows.push(row);
      row = [];
      field = '';
    } else {
      field += char;
    }
  }

  row.push(field.trim());
  if (row.some(Boolean)) rows.push(row);
  if (!rows.length) return { headers: [], rows: [], objects: [] };

  const headers = rows[0];
  const dataRows = rows.slice(1).filter((cells) => cells.some(Boolean));
  return {
    headers,
    rows: dataRows,
    objects: dataRows.map((cells, index) => ({
      rowNumber: index + 2,
      cells,
      values: Object.fromEntries(headers.map((header, cellIndex) => [header, cells[cellIndex] || ''])),
    })),
  };
};
const escapeCsvCell = (value = '') => {
  const text = String(value ?? '');
  if (!/[",\n\r]/.test(text)) return text;
  return `"${text.replace(/"/g, '""')}"`;
};
const buildQuestionBankUploadTemplateCsv = () =>
  `${QUESTION_BANK_UPLOAD_COLUMNS.map(escapeCsvCell).join(',')}\n`;
const countQuestionBankUploadDataRows = (rawText = '') => {
  const text = String(rawText || '').replace(/^\uFEFF/, '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  let rows = 0;
  let field = '';
  let rowHasContent = false;
  let inQuotes = false;

  for (let index = 0; index < text.length; index += 1) {
    const char = text[index];
    const next = text[index + 1];
    if (char === '"' && inQuotes && next === '"') {
      field += '"';
      index += 1;
    } else if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === '\n' && !inQuotes) {
      if (rowHasContent || field.trim()) rows += 1;
      field = '';
      rowHasContent = false;
    } else {
      field += char;
      if (!/\s/.test(char)) rowHasContent = true;
    }
  }

  if (rowHasContent || field.trim()) rows += 1;
  return Math.max(0, rows - 1);
};
const makeQuestionBankUploadTemplateFilename = (target = QUESTION_BANK_SYNC_TARGETS[0]) =>
  `${String(target.sheetName || target.gameName || 'question-bank')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '') || 'question-bank'}-upload-template.csv`;
const makeQuestionBankUploadSourceLabel = (target = QUESTION_BANK_SYNC_TARGETS[0], fileName = '', rawText = '') => {
  const sourceName = `${target.sheetName || target.gameName || 'question-bank'} ${fileName || 'csv-upload'}`
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80) || 'question-bank-upload';
  let hash = 2166136261;
  const text = String(rawText || '');
  for (let index = 0; index < text.length; index += 1) {
    hash ^= text.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  return `firestoreUpload:${sourceName}:${(hash >>> 0).toString(36)}`;
};
