const makeQuestionBankPreflightKey = (value = '') =>
  normalizeText(value)
    .toLowerCase()
    .replace(/[’']/g, '')
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
const makeQuestionBankTemplateKey = (value = '') =>
  makeQuestionBankPreflightKey(value)
    .replace(/\bvariant\s+\d+\b/g, '')
    .replace(/\brow\s+\d+\b/g, '')
    .replace(/\bquestion\s+\d+\b/g, '')
    .replace(/\bq\s+\d+\b/g, '')
    .replace(/\s+/g, ' ')
