const buildMostLikelyRoundOutcome = (round = {}, outcomeOptions = {}) => {
  const useStoredPenalties = outcomeOptions.useStoredPenalties !== false;
  const jayVote = normalizeMostLikelyChoice(round?.actualAnswers?.jay ?? round?.answers?.jay?.ownAnswer ?? '');
  const kimVote = normalizeMostLikelyChoice(round?.actualAnswers?.kim ?? round?.answers?.kim?.ownAnswer ?? '');
  const jayMissingOwnAnswer = !Boolean(jayVote);
  const kimMissingOwnAnswer = !Boolean(kimVote);
  const bothVoted = Boolean(jayVote && kimVote);
  const agreed = bothVoted && jayVote === kimVote;
  const splitVote = bothVoted && jayVote !== kimVote;
  const jayDefaultPenalty = jayMissingOwnAnswer
    ? MOST_LIKELY_UNANSWERED_PENALTY
    : splitVote
      ? MOST_LIKELY_DISAGREE_PENALTY
      : 0;
  const kimDefaultPenalty = kimMissingOwnAnswer
    ? MOST_LIKELY_UNANSWERED_PENALTY
    : splitVote
      ? MOST_LIKELY_DISAGREE_PENALTY
      : 0;
  const jayStoredPenalty = useStoredPenalties ? getStoredPenaltyOverride(round?.penaltyAdded?.jay, round?.penalties?.jay) : null;
  const kimStoredPenalty = useStoredPenalties ? getStoredPenaltyOverride(round?.penaltyAdded?.kim, round?.penalties?.kim) : null;
  const jayPenalty = jayStoredPenalty ?? jayDefaultPenalty;
  const kimPenalty = kimStoredPenalty ?? kimDefaultPenalty;
  return {
    options: getMostLikelyOptions(),
    jayVote,
    kimVote,
    jayMissingOwnAnswer,
    kimMissingOwnAnswer,
    jayMissingResponse: jayMissingOwnAnswer,
    kimMissingResponse: kimMissingOwnAnswer,
    bothVoted,
    agreed,
    splitVote,
    jayPenalty,
    kimPenalty,
  };
};
const buildPutYourPointsRoundOutcome = (round = {}, outcomeOptions = {}) => {
  const useStoredPenalties = outcomeOptions.useStoredPenalties !== false;
  const stake = getPutYourPointsStake(round);
  const jayResult = normalizePutYourPointsResult(round?.putYourPointsResults?.jay);
  const kimResult = normalizePutYourPointsResult(round?.putYourPointsResults?.kim);
  const jayDefaultPenalty = jayResult === 'missed' ? stake : 0;
  const kimDefaultPenalty = kimResult === 'missed' ? stake : 0;
  const jayStoredPenalty = useStoredPenalties ? getStoredPenaltyOverride(round?.penaltyAdded?.jay, round?.penalties?.jay) : null;
  const kimStoredPenalty = useStoredPenalties ? getStoredPenaltyOverride(round?.penaltyAdded?.kim, round?.penalties?.kim) : null;
  return {
    stake,
    jayResult,
    kimResult,
    jayMatched: jayResult === 'matched',
    kimMatched: kimResult === 'matched',
    jayMissed: jayResult === 'missed',
    kimMissed: kimResult === 'missed',
    jayPenalty: jayStoredPenalty ?? jayDefaultPenalty,
    kimPenalty: kimStoredPenalty ?? kimDefaultPenalty,
    complete: Boolean(jayResult && kimResult),
  };
};
const collectAnalyticsSessionsForMode = (activeEntries = [], previousEntries = [], modePredicate = () => false) => {
  const mergedById = new Map();
  [...(activeEntries || []), ...(previousEntries || [])].forEach((entry) => {
    if (!entry?.id || !modePredicate(entry?.gameMode || 'standard', entry)) return;
    if (!mergedById.has(entry.id)) mergedById.set(entry.id, entry);
  });
  return [...mergedById.values()];
};
const getAnalyticsRoundsForSessions = (sessions = [], fallbackGameName = 'Game') =>
  sessions.flatMap((entry) =>
    normalizeStoredRounds(entry?.rounds || []).map((round) => ({
      ...round,
      gameId: entry.id,
      gameName: entry.name || entry.gameName || entry.joinCode || fallbackGameName,
    })),
  );
const summarizeAnalyticsSessions = (sessions = []) => ({
  sessionsTracked: sessions.length,
  totalGamesPlayed: sessions.filter((entry) => COMPLETED_GAME_STATUSES.includes(entry?.status || '')).length,
  activeGames: sessions.filter((entry) => ACTIVE_GAME_STATUSES.includes(entry?.status || '')).length,
});
const getRoundPenaltyForAnalytics = (round = {}, seat = 'jay') =>
  Number(round?.penaltyAdded?.[seat] ?? round?.scores?.[seat] ?? round?.penalties?.[seat] ?? 0) || 0;
const buildChoiceGuessGameAnalytics = ({
  sessions = [],
  fallbackGameName = 'Game',
  buildOutcome = () => ({}),
  seededChoices = [],
} = {}) => {
  const roundsData = getAnalyticsRoundsForSessions(sessions, fallbackGameName);
  const choiceCounts = new Map();
  seededChoices.forEach((option) => {
    if (option) choiceCounts.set(option, { option, jay: 0, kim: 0 });
  });
  const categoryStats = new Map();
  const totals = {
    ...summarizeAnalyticsSessions(sessions),
    totalQuestionsAnswered: roundsData.length,
    bothCorrect: 0,
    splitCorrect: 0,
    missedResponses: 0,
    jayCorrectGuesses: 0,
    kimCorrectGuesses: 0,
    jayWrongGuesses: 0,
    kimWrongGuesses: 0,
    jayMissingResponses: 0,
    kimMissingResponses: 0,
    jayPenaltyPoints: 0,
    kimPenaltyPoints: 0,
  };

  const recordChoice = (seatName, option) => {
    if (!option) return;
    const current = choiceCounts.get(option) || { option, jay: 0, kim: 0 };
    current[seatName] += 1;
    choiceCounts.set(option, current);
  };

  roundsData.forEach((round) => {
    const outcome = buildOutcome(round, { useStoredPenalties: false }) || {};
    const categoryKey = normalizeText(round?.category) || 'uncategorised';
    const categoryEntry = categoryStats.get(categoryKey) || {
      category: round?.category || 'Uncategorised',
      rounds: 0,
      bothCorrect: 0,
      splitCorrect: 0,
      missedResponses: 0,
      jayCorrect: 0,
      kimCorrect: 0,
      jayWrong: 0,
      kimWrong: 0,
      jayPenalty: 0,
      kimPenalty: 0,
    };
    categoryEntry.rounds += 1;

    const jayMissing = Boolean(outcome.jayMissingResponse);
    const kimMissing = Boolean(outcome.kimMissingResponse);
    const jayCorrect = Boolean(outcome.jayCorrect);
    const kimCorrect = Boolean(outcome.kimCorrect);

    if (jayCorrect) {
      totals.jayCorrectGuesses += 1;
      categoryEntry.jayCorrect += 1;
    } else if (jayMissing) {
      totals.jayMissingResponses += 1;
    } else {
      totals.jayWrongGuesses += 1;
      categoryEntry.jayWrong += 1;
    }

    if (kimCorrect) {
      totals.kimCorrectGuesses += 1;
      categoryEntry.kimCorrect += 1;
    } else if (kimMissing) {
      totals.kimMissingResponses += 1;
    } else {
      totals.kimWrongGuesses += 1;
      categoryEntry.kimWrong += 1;
    }

    if (jayCorrect && kimCorrect) {
      totals.bothCorrect += 1;
      categoryEntry.bothCorrect += 1;
    } else if (jayMissing || kimMissing) {
      totals.missedResponses += 1;
      categoryEntry.missedResponses += 1;
    } else if (jayCorrect !== kimCorrect) {
      totals.splitCorrect += 1;
      categoryEntry.splitCorrect += 1;
    }

    recordChoice('jay', outcome.jayActual);
    recordChoice('kim', outcome.kimActual);
    totals.jayPenaltyPoints += Number(outcome.jayPenalty || 0);
    totals.kimPenaltyPoints += Number(outcome.kimPenalty || 0);
    categoryEntry.jayPenalty += Number(outcome.jayPenalty || 0);
    categoryEntry.kimPenalty += Number(outcome.kimPenalty || 0);
    categoryStats.set(categoryKey, categoryEntry);
  });

  const jayAttempts = totals.jayCorrectGuesses + totals.jayWrongGuesses;
  const kimAttempts = totals.kimCorrectGuesses + totals.kimWrongGuesses;

  return {
    ...totals,
    jayAccuracy: jayAttempts ? Math.round((totals.jayCorrectGuesses / jayAttempts) * 100) : 0,
    kimAccuracy: kimAttempts ? Math.round((totals.kimCorrectGuesses / kimAttempts) * 100) : 0,
    choiceRows: [...choiceCounts.values()].sort((left, right) => (right.jay + right.kim) - (left.jay + left.kim) || left.option.localeCompare(right.option)),
    categoryRows: [...categoryStats.values()].sort(
      (left, right) =>
        right.rounds - left.rounds
        || right.splitCorrect - left.splitCorrect
        || left.category.localeCompare(right.category),
    ),
  };
};
const getCompatibilityAnalyticsBand = (score = 0) => {
  if (score >= 95) return 'strong';
  if (score >= 85) return 'close';
  if (score >= 70) return 'mixed';
  return 'low';
};
const COMPATIBILITY_ANALYTICS_BANDS = [
  { id: 'strong', label: '95%+', title: 'Strong match' },
  { id: 'close', label: '85-94%', title: 'Close match' },
  { id: 'mixed', label: '70-84%', title: 'Mixed match' },
  { id: 'low', label: '0-69%', title: 'Low match' },
];
const buildCompatibilityMeterAnalytics = (sessions = []) => {
  const roundsData = getAnalyticsRoundsForSessions(sessions, 'Compatibility Meter');
  const categoryStats = new Map();
  const bandCounts = Object.fromEntries(COMPATIBILITY_ANALYTICS_BANDS.map((band) => [band.id, 0]));
  const totals = {
    ...summarizeAnalyticsSessions(sessions),
    totalQuestionsAnswered: roundsData.length,
    totalScore: 0,
    highestScore: 0,
    lowestScore: roundsData.length ? 100 : 0,
    jayPenaltyPoints: sessions.reduce((sum, entry) => sum + Number(entry?.finalScores?.jay ?? entry?.totals?.jay ?? 0), 0),
    kimPenaltyPoints: sessions.reduce((sum, entry) => sum + Number(entry?.finalScores?.kim ?? entry?.totals?.kim ?? 0), 0),
  };

  roundsData.forEach((round) => {
    const outcome = buildCompatibilityRoundOutcome(round, { useStoredPenalties: false });
    const score = Number(outcome.score || 0);
    const bandId = getCompatibilityAnalyticsBand(score);
    const categoryKey = normalizeText(round?.category) || 'uncategorised';
    const categoryEntry = categoryStats.get(categoryKey) || {
      category: round?.category || 'Uncategorised',
      rounds: 0,
      totalScore: 0,
      strong: 0,
      close: 0,
      mixed: 0,
      low: 0,
      jayPenalty: 0,
      kimPenalty: 0,
    };
    categoryEntry.rounds += 1;
    categoryEntry.totalScore += score;
    categoryEntry[bandId] += 1;
    categoryEntry.jayPenalty += Number(outcome.jayPenalty || 0);
    categoryEntry.kimPenalty += Number(outcome.kimPenalty || 0);
    categoryStats.set(categoryKey, categoryEntry);

    totals.totalScore += score;
    totals.highestScore = Math.max(totals.highestScore, score);
    totals.lowestScore = Math.min(totals.lowestScore, score);
    bandCounts[bandId] += 1;
  });

  return {
    ...totals,
    averageScore: roundsData.length ? Math.round(totals.totalScore / roundsData.length) : 0,
    bandRows: COMPATIBILITY_ANALYTICS_BANDS.map((band) => ({
      ...band,
      count: bandCounts[band.id] || 0,
    })),
    categoryRows: [...categoryStats.values()]
      .map((row) => ({ ...row, averageScore: row.rounds ? Math.round(row.totalScore / row.rounds) : 0 }))
      .sort((left, right) => right.rounds - left.rounds || right.averageScore - left.averageScore || left.category.localeCompare(right.category)),
  };
};
const buildMemoryLaneAnalytics = (sessions = []) => {
  const roundsData = getAnalyticsRoundsForSessions(sessions, 'Memory Lane');
  const categoryStats = new Map();
  const typeStats = new Map();
  const totals = {
    ...summarizeAnalyticsSessions(sessions),
    totalQuestionsAnswered: roundsData.length,
    memoryPromptRounds: 0,
    recallRounds: 0,
    recallCorrect: 0,
    recallWrong: 0,
    jayPenaltyPoints: 0,
    kimPenaltyPoints: 0,
    jayRoundWins: 0,
    kimRoundWins: 0,
    tiedRounds: 0,
  };

  roundsData.forEach((round) => {
    const isRecall = isMemoryLaneRecallRound(round);
    const categoryKey = normalizeText(round?.category) || 'uncategorised';
    const typeKey = normalizeText(round?.roundType) || 'unknown';
    const jayPenalty = getRoundPenaltyForAnalytics(round, 'jay');
    const kimPenalty = getRoundPenaltyForAnalytics(round, 'kim');
    const categoryEntry = categoryStats.get(categoryKey) || {
      category: round?.category || 'Uncategorised',
      rounds: 0,
      recallRounds: 0,
      memoryPromptRounds: 0,
      jayPenalty: 0,
      kimPenalty: 0,
    };
    const typeEntry = typeStats.get(typeKey) || {
      roundType: typeKey,
      rounds: 0,
      recallRounds: 0,
      jayPenalty: 0,
      kimPenalty: 0,
    };
    categoryEntry.rounds += 1;
    typeEntry.rounds += 1;
    categoryEntry.jayPenalty += jayPenalty;
    categoryEntry.kimPenalty += kimPenalty;
    typeEntry.jayPenalty += jayPenalty;
    typeEntry.kimPenalty += kimPenalty;
    totals.jayPenaltyPoints += jayPenalty;
    totals.kimPenaltyPoints += kimPenalty;

    if (round?.winner === 'jay') totals.jayRoundWins += 1;
    else if (round?.winner === 'kim') totals.kimRoundWins += 1;
    else totals.tiedRounds += 1;

    if (isRecall) {
      totals.recallRounds += 1;
      categoryEntry.recallRounds += 1;
      typeEntry.recallRounds += 1;
      const correctKey = normalizeIdentity(round?.correctAnswer || '');
      seats.forEach((seatName) => {
        const answerKey = normalizeIdentity(round?.actualAnswers?.[seatName] ?? round?.answers?.[seatName]?.ownAnswer ?? '');
        if (!correctKey || !answerKey) return;
        if (answerKey === correctKey) totals.recallCorrect += 1;
        else totals.recallWrong += 1;
      });
    } else {
      totals.memoryPromptRounds += 1;
      categoryEntry.memoryPromptRounds += 1;
    }

    categoryStats.set(categoryKey, categoryEntry);
    typeStats.set(typeKey, typeEntry);
  });

  const recallAttempts = totals.recallCorrect + totals.recallWrong;
  return {
    ...totals,
    recallAccuracy: recallAttempts ? Math.round((totals.recallCorrect / recallAttempts) * 100) : 0,
    categoryRows: [...categoryStats.values()].sort((left, right) => right.rounds - left.rounds || left.category.localeCompare(right.category)),
    typeRows: [...typeStats.values()].sort((left, right) => right.rounds - left.rounds || left.roundType.localeCompare(right.roundType)),
  };
};
const buildAutoScoredRoundPenaltyMap = (gameMode = 'standard', round = {}, options = {}) => {
  if (isTrueFalseGameMode(gameMode)) {
    const outcome = buildTrueFalseRoundOutcome(round, options);
    return { jay: outcome.jayPenalty, kim: outcome.kimPenalty };
  }
  if (isThisOrThatGameMode(gameMode)) {
    const outcome = buildThisOrThatRoundOutcome(round, options);
    return { jay: outcome.jayPenalty, kim: outcome.kimPenalty };
  }
  if (isRedFlagGreenFlagGameMode(gameMode)) {
    const outcome = buildRedFlagGreenFlagRoundOutcome(round, options);
    return { jay: outcome.jayPenalty, kim: outcome.kimPenalty };
  }
  if (isCompatibilityMeterGameMode(gameMode)) {
    const outcome = buildCompatibilityRoundOutcome(round, options);
    return { jay: outcome.jayPenalty, kim: outcome.kimPenalty };
  }
  if (isMostLikelyGameMode(gameMode) && isMostLikelyVoteRound(round)) {
    const outcome = buildMostLikelyRoundOutcome(round, options);
    return { jay: outcome.jayPenalty, kim: outcome.kimPenalty };
  }
  if (isPutYourPointsGameMode(gameMode)) {
    const outcome = buildPutYourPointsRoundOutcome(round, options);
    return { jay: outcome.jayPenalty, kim: outcome.kimPenalty };
  }
  return null;
};
const buildRoundPenaltyMapForArchive = (gameMode = 'standard', round = {}, manualPenaltyDraft = defaultPenaltyDraft) =>
  buildAutoScoredRoundPenaltyMap(gameMode, round, { useStoredPenalties: isPutYourPointsGameMode(gameMode) })
  || toPenaltyScores(manualPenaltyDraft || defaultPenaltyDraft);
const buildPendingRoundPenaltyMapForFinalize = (gameMode = 'standard', round = {}, pendingRoundPenaltyOverride = null) =>
  buildAutoScoredRoundPenaltyMap(gameMode, round, { useStoredPenalties: isPutYourPointsGameMode(gameMode) })
  || {
    jay: toScore(pendingRoundPenaltyOverride?.jay ?? round?.penalties?.jay ?? 0),
    kim: toScore(pendingRoundPenaltyOverride?.kim ?? round?.penalties?.kim ?? 0),
  };
const getRetiredQuestionIdsForGame = (game = {}) => collectGameQuestionIds([game]);
const getLifetimeRollbackForGame = (game = {}) => {
  const gameMode = game?.gameMode || 'standard';
  if (isHoldemGameMode(gameMode)) {
    return {
      jay: -Number(game?.holdemStats?.netMovementJay || 0),
      kim: -Number(game?.holdemStats?.netMovementKim || 0),
    };
  }
  const hasAppliedLifetimePoints =
    Boolean(game?.lifetimePointsApplied)
    || (
      isMostLikelyGameMode(gameMode)
      && COMPLETED_GAME_STATUSES.includes(game?.status || '')
      && (Number(game?.finalScores?.jay ?? game?.totals?.jay ?? 0) !== 0 || Number(game?.finalScores?.kim ?? game?.totals?.kim ?? 0) !== 0)
    );
  if (!hasAppliedLifetimePoints) {
    return { jay: 0, kim: 0 };
  }
  if (gameMode === 'quiz') {
    return {
      jay: -Number(game?.wagerSettlement?.jayShift || 0),
      kim: -Number(game?.wagerSettlement?.kimShift || 0),
    };
  }
  return {
    jay: -Number(game?.finalScores?.jay ?? game?.totals?.jay ?? 0),
    kim: -Number(game?.finalScores?.kim ?? game?.totals?.kim ?? 0),
  };
};
const hasReadySeat = (round = {}, seat = '') => Boolean(round?.ready?.[seat]);
const answerDraftStorageKey = (gameId = '', roundId = '', seat = '') =>
  gameId && roundId && seat ? `kjk-answer-draft:${gameId}:${roundId}:${seat}` : '';
const answerDraftMemoryStore = new Map();
const answerDraftTouchedStore = new Set();
const activeAnswerInputMemory = { key: '', field: '', selectionStart: 0, selectionEnd: 0 };
const markAnswerDraftTouched = (key = '') => {
  if (key) answerDraftTouchedStore.add(key);
};
const clearAnswerDraftTouched = (key = '') => {
  if (key) answerDraftTouchedStore.delete(key);
};
const wasAnswerDraftTouched = (key = '') => Boolean(key && answerDraftTouchedStore.has(key));
const safeLocalStorageSet = (key = '', value = '') => {
  if (!key || typeof window === 'undefined') return false;
  try {
    window.localStorage.setItem(key, value);
    return true;
  } catch {
    return false;
  }
};
const readPendingDeletedGameIds = () => {
  if (typeof window === 'undefined') return [];
  try {
    const raw = window.localStorage.getItem(pendingDeletedGamesKey);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed.map((value) => String(value || '')).filter(Boolean) : [];
  } catch {
    return [];
  }
};
const writePendingDeletedGameIds = (ids = []) => {
  if (typeof window === 'undefined') return false;
  try {
    const normalizedIds = [...new Set((ids || []).map((value) => String(value || '')).filter(Boolean))];
    if (!normalizedIds.length) {
      window.localStorage.removeItem(pendingDeletedGamesKey);
      return true;
    }
    return safeLocalStorageSet(pendingDeletedGamesKey, JSON.stringify(normalizedIds));
  } catch {
    return false;
  }
};
const isMobileDashboardViewport = () => {
  if (typeof window === 'undefined' || !window.matchMedia) return false;
  try {
    return window.matchMedia('(max-width: 900px)').matches;
  } catch {
    return false;
  }
};
const setMobilePostAuthDashboardDefault = () => {
  if (!isMobileDashboardViewport()) return false;
  return safeLocalStorageSet('kjk-dashboard-tab', 'gameLobby');
};
const readStoredAnswerDraft = (key = '') => {
  if (!key || typeof window === 'undefined') return null;
  const memoryDraft = answerDraftMemoryStore.get(key);
  if (memoryDraft) return memoryDraft;
  try {
    const raw = window.localStorage.getItem(key);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    return {
      ownAnswer: String(parsed?.ownAnswer ?? ''),
      guessedOther: String(parsed?.guessedOther ?? ''),
    };
  } catch {
    return null;
  }
};
const writeStoredAnswerDraft = (key = '', draft = {}) => {
  if (!key || typeof window === 'undefined') return;
  const normalizedDraft = {
    ownAnswer: String(draft?.ownAnswer ?? ''),
    guessedOther: String(draft?.guessedOther ?? ''),
  };
  answerDraftMemoryStore.set(key, normalizedDraft);
  safeLocalStorageSet(key, JSON.stringify(normalizedDraft));
};

const stableRoundIdentityKey = (round = {}) =>
  normalizeText(round?.questionId)
  || String(round?.number || '')
  || sanitizeNoteKey(round?.question || '')
  || '';

const stableRoomSnapshotValue = (game = {}) => {
  if (!game) return null;
  const round = game.currentRound || null;
  return {
    id: game.id || '',
    status: game.status || '',
    endedAt: game.endedAt || null,
    joinCode: game.joinCode || game.roomCode || game.code || '',
    hostUid: game.hostUid || '',
    gameMode: game.gameMode || 'standard',
    questionBankType: game.questionBankType || 'game',
    seats: game.seats || {},
    playerProfiles: game.playerProfiles || {},
    totals: game.totals || {},
    quizTotals: game.quizTotals || {},
    quizWagers: game.quizWagers || {},
    quizWagerAgreement: game.quizWagerAgreement || null,
    quizReadyState: game.quizReadyState || null,
    holdemState: game.holdemState || null,
    holdemStats: game.holdemStats || null,
    roundsPlayed: Number(game.roundsPlayed || 0),
    requestedQuestionCount: Number(game.requestedQuestionCount || 0),
    actualQuestionCount: Number(game.actualQuestionCount || 0),
    questionQueueIds: game.questionQueueIds || [],
    retiredQuestionIds: game.retiredQuestionIds || [],
    usedQuestionIds: game.usedQuestionIds || [],
    currentRound: round
      ? {
          ...round,
          updatedAt: undefined,
        }
      : null,
  };
};

const areStableRoomSnapshotsEqual = (left, right) =>
  JSON.stringify(stableRoomSnapshotValue(left)) === JSON.stringify(stableRoomSnapshotValue(right));
const areRoundAnswerSnapshotsEqual = (left = {}, right = {}) =>
  String(left?.ownAnswer ?? '') === String(right?.ownAnswer ?? '')
  && String(left?.guessedOther ?? '') === String(right?.guessedOther ?? '')
  && String(left?.submittedBy ?? '') === String(right?.submittedBy ?? '')
  && String(left?.submittedAt ?? '') === String(right?.submittedAt ?? '')
  && String(left?.finalResult ?? '') === String(right?.finalResult ?? '')
  && String(left?.originalSystemResult ?? '') === String(right?.originalSystemResult ?? '')
  && Boolean(left?.wasCorrect) === Boolean(right?.wasCorrect)
  && Number(left?.pointsAwarded || 0) === Number(right?.pointsAwarded || 0)
  && Number(left?.timerValue || 0) === Number(right?.timerValue || 0);

const isJoinableGameSnapshot = (data = {}) => {
  if (!data) return false;
  const status = data.status || 'active';
  return ACTIVE_GAME_STATUSES.includes(status)
    && !COMPLETED_GAME_STATUSES.includes(status)
    && !data.endedAt;
};

const hasObjectFields = (value) =>
  Boolean(value && typeof value === 'object' && !Array.isArray(value) && Object.keys(value).length);

const mergeRoomIdentitySnapshot = (currentGame = {}, incomingGame = {}) => {
  const currentSeats = hasObjectFields(currentGame?.seats) ? currentGame.seats : {};
  const incomingSeats = hasObjectFields(incomingGame?.seats) ? incomingGame.seats : {};
  const currentProfiles = hasObjectFields(currentGame?.playerProfiles) ? currentGame.playerProfiles : {};
  const incomingProfiles = hasObjectFields(incomingGame?.playerProfiles) ? incomingGame.playerProfiles : {};
  return {
    ...incomingGame,
    hostUid: incomingGame?.hostUid || currentGame?.hostUid || '',
    hostDisplayName: incomingGame?.hostDisplayName || currentGame?.hostDisplayName || '',
    hostPhotoURL: incomingGame?.hostPhotoURL || currentGame?.hostPhotoURL || '',
    seats: hasObjectFields(incomingSeats) ? { ...currentSeats, ...incomingSeats } : currentSeats,
    playerUids: Array.isArray(incomingGame?.playerUids) && incomingGame.playerUids.length
      ? incomingGame.playerUids
      : (Array.isArray(currentGame?.playerUids) ? currentGame.playerUids : []),
    playerProfiles: hasObjectFields(incomingProfiles) ? { ...currentProfiles, ...incomingProfiles } : currentProfiles,
    pairId: incomingGame?.pairId || currentGame?.pairId || '',
    gameMode: incomingGame?.gameMode || currentGame?.gameMode || 'standard',
    questionBankType: incomingGame?.questionBankType || currentGame?.questionBankType || getQuestionBankTypeForGameMode(incomingGame?.gameMode || currentGame?.gameMode || 'standard'),
  };
};

const mergeActiveRoundSnapshot = (currentGame, incomingGame) => {
  if (currentGame?.id === incomingGame?.id && currentGame?.currentRound && !incomingGame?.currentRound) {
    const incomingStatus = incomingGame?.status || 'active';
    if (!COMPLETED_GAME_STATUSES.includes(incomingStatus) && !incomingGame?.endedAt) {
      return {
        ...mergeRoomIdentitySnapshot(currentGame, incomingGame),
        currentRound: currentGame.currentRound,
      };
    }
  }
  if (!currentGame?.currentRound || !incomingGame?.currentRound) {
    if (currentGame?.id === incomingGame?.id) {
      const preserveCurrentAgreement = shouldPreserveCurrentQuizAgreement(currentGame, incomingGame);
      const isHoldemRoom = isHoldemGameMode(incomingGame?.gameMode || currentGame?.gameMode || 'standard');
      const mergedGame = {
        ...mergeRoomIdentitySnapshot(currentGame, incomingGame),
        ...(isHoldemRoom
          ? {
              holdemState: mergeHoldemSnapshotState(currentGame?.holdemState || null, incomingGame?.holdemState || null),
            }
          : {}),
        quizWagerAgreement: preserveCurrentAgreement
          ? (currentGame?.quizWagerAgreement || incomingGame?.quizWagerAgreement || null)
          : (incomingGame?.quizWagerAgreement || currentGame?.quizWagerAgreement || null),
        quizWagers: preserveCurrentAgreement
          ? (currentGame?.quizWagers || incomingGame?.quizWagers || {})
          : (incomingGame?.quizWagers || currentGame?.quizWagers || {}),
        // Setup readiness is fully snapshot-driven; don't preserve optimistic
        // local flags over the room document.
        quizReadyState: incomingGame?.quizReadyState || null,
      };
      return areStableRoomSnapshotsEqual(currentGame, mergedGame)
        ? currentGame
        : mergedGame;
    }
    return incomingGame;
  }
  if (currentGame.id !== incomingGame.id) return incomingGame;
  const currentRound = currentGame.currentRound || {};
  const incomingRound = incomingGame.currentRound || {};
  const currentIdentity = stableRoundIdentityKey(currentRound);
  const incomingIdentity = stableRoundIdentityKey(incomingRound);
  const isQuizLiveRound = (incomingGame?.gameMode || currentGame?.gameMode || 'standard') === 'quiz';
  if (!incomingIdentity) {
    return {
      ...incomingGame,
      currentRound: currentRound,
    };
  }
  const sameByIdentity = Boolean(currentIdentity && incomingIdentity && currentIdentity === incomingIdentity);
  const sameByNumber = !isQuizLiveRound
    && Boolean(currentRound.number && incomingRound.number && Number(currentRound.number) === Number(incomingRound.number));
  const sameByPrompt =
    normalizeText(currentRound.question || '')
    && normalizeText(currentRound.question || '') === normalizeText(incomingRound.question || '')
    && normalizeText(currentRound.roundType || '') === normalizeText(incomingRound.roundType || '');
  const isSameLiveRound = sameByIdentity || sameByNumber || sameByPrompt;
  if (!isSameLiveRound) return incomingGame;
  const incomingGameMode = incomingGame?.gameMode || currentGame?.gameMode || 'standard';
  const currentAnswers = currentGame.currentRound.answers || {};
  const incomingAnswers = incomingGame.currentRound.answers || {};
  const preserveOptimisticAnswers = incomingRound.status === 'open' && currentRound.status === 'open';
  const nextAnswers = preserveOptimisticAnswers
    ? {
        jay: hasRoundAnswerSubmittedForMode(incomingGameMode, incomingGame.currentRound, 'jay') ? incomingAnswers.jay : currentAnswers.jay,
        kim: hasRoundAnswerSubmittedForMode(incomingGameMode, incomingGame.currentRound, 'kim') ? incomingAnswers.kim : currentAnswers.kim,
      }
    : {
        ...(hasRoundAnswerSubmittedForMode(incomingGameMode, incomingGame.currentRound, 'jay') ? { jay: incomingAnswers.jay } : {}),
        ...(hasRoundAnswerSubmittedForMode(incomingGameMode, incomingGame.currentRound, 'kim') ? { kim: incomingAnswers.kim } : {}),
      };
  const stableRoundFields =
    currentGame.currentRound.status === incomingGame.currentRound.status
    && currentGame.currentRound.questionId === incomingGame.currentRound.questionId
    && currentGame.currentRound.question === incomingGame.currentRound.question
    && currentGame.currentRound.category === incomingGame.currentRound.category
    && currentGame.currentRound.roundType === incomingGame.currentRound.roundType
    && currentGame.currentRound.defaultAnswerType === incomingGame.currentRound.defaultAnswerType
    && currentGame.currentRound.correctAnswer === incomingGame.currentRound.correctAnswer
    && currentGame.currentRound.normalizedCorrectAnswer === incomingGame.currentRound.normalizedCorrectAnswer
    && currentGame.currentRound.quizTimerSeconds === incomingGame.currentRound.quizTimerSeconds
    && currentGame.currentRound.quizTimerStartedAt === incomingGame.currentRound.quizTimerStartedAt
    && currentGame.currentRound.quizTimerEndsAt === incomingGame.currentRound.quizTimerEndsAt
    && Number(currentGame.currentRound.putYourPointsStake || 0) === Number(incomingGame.currentRound.putYourPointsStake || 0)
    && JSON.stringify(currentGame.currentRound.putYourPointsStakeSequence || []) === JSON.stringify(incomingGame.currentRound.putYourPointsStakeSequence || [])
    && JSON.stringify(currentGame.currentRound.putYourPointsResults || {}) === JSON.stringify(incomingGame.currentRound.putYourPointsResults || {})
    && JSON.stringify(currentGame.currentRound.multipleChoiceOptions || []) === JSON.stringify(incomingGame.currentRound.multipleChoiceOptions || [])
    && currentGame.currentRound.penalties?.jay === incomingGame.currentRound.penalties?.jay
    && currentGame.currentRound.penalties?.kim === incomingGame.currentRound.penalties?.kim
    && JSON.stringify(currentGame.currentRound.ready || {}) === JSON.stringify(incomingGame.currentRound.ready || {})
    && JSON.stringify(currentGame.currentRound.nextReady || {}) === JSON.stringify(incomingGame.currentRound.nextReady || {})
    && JSON.stringify(currentGame.currentRound.overrideRequests || {}) === JSON.stringify(incomingGame.currentRound.overrideRequests || {})
    && areRoundAnswerSnapshotsEqual(currentAnswers.jay, nextAnswers.jay)
    && areRoundAnswerSnapshotsEqual(currentAnswers.kim, nextAnswers.kim);
  const mergedRound = {
    ...currentRound,
    ...incomingRound,
    questionId: incomingRound.questionId || currentRound.questionId || '',
    question: incomingRound.question || currentRound.question || '',
    category: incomingRound.category || currentRound.category || '',
    roundType: incomingRound.roundType || currentRound.roundType || '',
    defaultAnswerType: incomingRound.defaultAnswerType || currentRound.defaultAnswerType || '',
    multipleChoiceOptions: Array.isArray(incomingRound.multipleChoiceOptions) && incomingRound.multipleChoiceOptions.length
      ? incomingRound.multipleChoiceOptions
      : currentRound.multipleChoiceOptions || [],
    penalties: {
      ...(currentRound.penalties || {}),
      ...(incomingRound.penalties || {}),
    },
    ready: {
      ...(currentRound.ready || {}),
      ...(incomingRound.ready || {}),
    },
    nextReady: {
      ...(currentRound.nextReady || {}),
      ...(incomingRound.nextReady || {}),
    },
    overrideRequests: {
      ...(currentRound.overrideRequests || {}),
      ...(incomingRound.overrideRequests || {}),
    },
    putYourPointsStake: incomingRound.putYourPointsStake ?? currentRound.putYourPointsStake,
    putYourPointsStakeSequence: Array.isArray(incomingRound.putYourPointsStakeSequence) && incomingRound.putYourPointsStakeSequence.length
      ? incomingRound.putYourPointsStakeSequence
      : currentRound.putYourPointsStakeSequence || [],
    putYourPointsResults: {
      ...(currentRound.putYourPointsResults || {}),
      ...(incomingRound.putYourPointsResults || {}),
    },
    answers: nextAnswers,
  };
  const mergedGame = {
    ...mergeRoomIdentitySnapshot(currentGame, incomingGame),
    currentRound: stableRoundFields
      ? currentGame.currentRound
      : mergedRound,
  };
  return areStableRoomSnapshotsEqual(currentGame, mergedGame) ? currentGame : mergedGame;
};

const getPlayedQuestionIdsForGame = (game = {}) => {
  const archivedRoundIds = mergeUniqueIds((game?.rounds || []).map((round) => round?.questionId));
  if (archivedRoundIds.length) return archivedRoundIds;
  return mergeUniqueIds(game?.usedQuestionIds || []);
};

const getCompletedGameDisplayCount = (game = {}) => {
  if (isHoldemGameMode(game?.gameMode || 'standard')) {
    return Math.max(0, Number(game?.holdemStats?.handsPlayed || 0), Number(game?.roundsPlayed || 0));
  }
  const answeredRoundsLength = Array.isArray(game?.rounds) ? game.rounds.length : 0;
  const roundsPlayed = Math.max(0, Number(game?.roundsPlayed || 0));
  const playedQuestionIdsLength = getPlayedQuestionIdsForGame(game).length;
  if (answeredRoundsLength) return answeredRoundsLength;
  if (roundsPlayed) return Math.min(Math.max(playedQuestionIdsLength, roundsPlayed), roundsPlayed);
  return playedQuestionIdsLength;
};

const isFirestoreRateLimitedError = (error = null) => {
  const normalizedMessage = normalizeText(error?.message || error || '').toLowerCase();
  const normalizedCode = normalizeText(error?.code || error?.name || '').toLowerCase();
  return (
    normalizedMessage.includes('resource exhausted')
    || normalizedMessage.includes('resource-exhausted')
    || normalizedMessage.includes('quota exceeded')
    || normalizedMessage.includes('quotaexceeded')
    || normalizedMessage.includes('too many requests')
    || normalizedCode.includes('resource-exhausted')
    || normalizedCode.includes('quota-exceeded')
  );
};

const isLocalStorageQuotaError = (error = null) => {
  const normalizedMessage = normalizeText(error?.message || error || '').toLowerCase();
  const normalizedCode = normalizeText(error?.code || error?.name || '').toLowerCase();
  if (isFirestoreRateLimitedError(error)) return false;
  return (
    normalizedCode.includes('quotaexceedederror')
    || normalizedMessage.includes('storage quota')
    || (normalizedMessage.includes('storage') && normalizedMessage.includes('quota'))
  );
};

const getGameQuestionGoal = (game, rounds = []) => {
  const playedRounds = Math.max(Number(game?.roundsPlayed || 0), Array.isArray(rounds) ? rounds.length : 0);
  const queuedRounds = Array.isArray(game?.questionQueueIds) ? game.questionQueueIds.filter(Boolean).length : 0;
  const currentRoundCount = game?.currentRound ? 1 : 0;
  const actualQuestionCount = Math.max(0, Number(game?.actualQuestionCount || 0));
  if (actualQuestionCount > 0) return actualQuestionCount;
  const inFlightQuestionCount = playedRounds + queuedRounds + currentRoundCount;
  if (inFlightQuestionCount > 0) return inFlightQuestionCount;
  return Math.max(Number(game?.requestedQuestionCount || 0), playedRounds, 0);
};

const scoreMapHasPoints = (scores = null) =>
  Number(scores?.jay || 0) !== 0 || Number(scores?.kim || 0) !== 0;

const getRoundHistoryFinalScores = (roundsData = []) => {
  const roundsList = Array.isArray(roundsData) ? roundsData.filter(Boolean) : [];
  if (!roundsList.length) return null;
  const finalScores = getRoundPenaltyTotals(roundsList[roundsList.length - 1]);
  return {
    jay: Number(finalScores?.jay || 0),
    kim: Number(finalScores?.kim || 0),
  };
};

const shouldDerivePenaltyScoresFromRoundHistory = (gameMode = 'standard') =>
  !isQuizGameMode(gameMode)
  && !isHoldemGameMode(gameMode)
  && !isCompatibilityMeterGameMode(gameMode);

const buildGameLibraryEntry = (id, data = {}, roundsData = []) => {
  const status = data.status || 'active';
  const gameMode = resolveGameMode(data.gameMode || data.questionBankType || 'standard');
  const isHoldemGame = isHoldemGameMode(gameMode);
  const holdemStats = data.holdemStats || defaultHoldemStats();
  const holdemState = data.holdemState || null;
  const selectedQuestionsLength = Array.isArray(data.questionQueueIds) ? data.questionQueueIds.filter(Boolean).length : 0;
  const retiredQuestionIds = Array.isArray(data.retiredQuestionIds) ? data.retiredQuestionIds.filter(Boolean) : [];
  const usedQuestionIds = Array.isArray(data.usedQuestionIds) ? data.usedQuestionIds.filter(Boolean) : [];
  const answeredRoundsLength = isHoldemGame ? 0 : roundsData.length;
  const displayedQuestionCount = isHoldemGame
    ? Math.max(0, Number(holdemStats?.handsPlayed || 0), Number(data.roundsPlayed || 0))
    : COMPLETED_GAME_STATUSES.includes(status)
      ? getCompletedGameDisplayCount({
          rounds: roundsData,
          roundsPlayed: data.roundsPlayed || roundsData.length,
          usedQuestionIds,
        })
      : Math.max(
          Number(data.actualQuestionCount || 0),
          Number(data.requestedQuestionCount || 0),
          answeredRoundsLength + selectedQuestionsLength + (data.currentRound ? 1 : 0),
          0,
        );
  const defaultHoldemFinals = holdemState?.lastSettledBalances || { jay: 0, kim: 0 };
  const storedFinalScores = data.finalScores || data.totals || (roundsData.length ? roundsData.at(-1)?.totalsAfterRound || { jay: 0, kim: 0 } : { jay: 0, kim: 0 });
  const roundHistoryFinalScores = shouldDerivePenaltyScoresFromRoundHistory(gameMode)
    && COMPLETED_GAME_STATUSES.includes(status)
    ? getRoundHistoryFinalScores(roundsData)
    : null;
  const finalScores = isHoldemGame
    ? (data.finalScores || data.totals || defaultHoldemFinals)
    : roundHistoryFinalScores && (scoreMapHasPoints(roundHistoryFinalScores) || !scoreMapHasPoints(storedFinalScores))
      ? roundHistoryFinalScores
      : storedFinalScores;
  const penaltyScoreWinner = Number(finalScores.jay || 0) === Number(finalScores.kim || 0)
    ? 'tie'
    : Number(finalScores.jay || 0) < Number(finalScores.kim || 0)
      ? 'jay'
      : 'kim';
  const quizTotals = data.quizTotals || { jay: 0, kim: 0 };
  const quizScoreWinner = Number(quizTotals.jay || 0) === Number(quizTotals.kim || 0)
    ? 'tie'
    : Number(quizTotals.jay || 0) > Number(quizTotals.kim || 0)
      ? 'jay'
      : 'kim';
  const storedWinner = ['jay', 'kim', 'tie'].includes(data.winner) ? data.winner : '';
  const storedQuizWinner = ['jay', 'kim', 'tie'].includes(data.quizWinner) ? data.quizWinner : '';
  const normalizedQuizWinner = storedQuizWinner && !(storedQuizWinner === 'tie' && quizScoreWinner !== 'tie')
    ? storedQuizWinner
    : quizScoreWinner;
  const derivedWinner = gameMode === 'quiz' ? normalizedQuizWinner : penaltyScoreWinner;
  const normalizedWinner = storedWinner && !(storedWinner === 'tie' && derivedWinner !== 'tie')
    ? storedWinner
    : derivedWinner;
  const currentPlayerList = [
    data.playerProfiles?.[data.seats?.jay]?.displayName || 'Jay',
    data.playerProfiles?.[data.seats?.kim]?.displayName || 'Kim',
  ].filter(Boolean);
  const holdemWinner = getHoldemSessionWinner(holdemStats, finalScores);

  return {
    id,
    joinCode: data.roomCode || data.joinCode || data.code,
    name: data.gameName || `Game ${data.roomCode || data.joinCode || data.code}`,
    status,
    players: currentPlayerList,
    currentRound: data.currentRound?.number || null,
    currentRoundStatus: data.currentRound?.status || '',
    currentRoundQuestion: data.currentRound?.question || '',
    currentRoundCategory: data.currentRound?.category || '',
    currentRoundType: data.currentRound?.roundType || '',
    currentRoundAnswerSeats: seats.filter((seat) => hasRoundAnswerSubmittedForMode(gameMode, data.currentRound || {}, seat)),
    createdAt: data.createdAt || null,
    endedAt: data.endedAt || null,
    endedBy: data.endedBy || '',
    finalScores,
    winner: isHoldemGame ? holdemWinner : normalizedWinner,
    quizTotals,
    quizWinner: gameMode === 'quiz' ? normalizedQuizWinner : data.quizWinner || '',
    wagerSettlement: data.wagerSettlement || null,
    roundsPlayed: isHoldemGame ? Number(holdemStats?.handsPlayed || data.roundsPlayed || 0) : (data.roundsPlayed || roundsData.length),
    rounds: roundsData,
    questionQueueIds: data.questionQueueIds || [],
    retiredQuestionIds,
    usedQuestionIds,
    seats: data.seats || {},
    playerProfiles: data.playerProfiles || {},
    gameMode,
    questionBankType: data.questionBankType || getQuestionBankTypeForGameMode(gameMode),
    requestedQuestionCount: Number(data.requestedQuestionCount || 0),
    actualQuestionCount: displayedQuestionCount,
    displayedQuestionCount,
    selectedQuestionsLength,
    answeredRoundsLength,
    roundHistoryLength: roundsData.length,
    currentQuestionIndex: data.currentRound?.number || null,
    lifetimePointsApplied: Boolean(data.lifetimePointsApplied),
    holdemState,
    holdemStats,
    holdemHandsPlayed: Number(holdemStats?.handsPlayed || 0),
  };
};

const upsertGameLibraryEntry = (entries = [], nextEntry = null) => {
  if (!nextEntry?.id) return entries;
  const seen = new Set();
  const merged = [nextEntry, ...entries].filter((entry) => {
    if (!entry?.id || seen.has(entry.id)) return false;
    seen.add(entry.id);
    return true;
  });
  merged.sort((left, right) =>
    getRecordTime(right?.createdAt || right?.endedAt || 0) - getRecordTime(left?.createdAt || left?.endedAt || 0),
  );
  return merged;
};

const chunkArray = (items, size = 400) => {
  const chunks = [];
  for (let index = 0; index < items.length; index += size) {
    chunks.push(items.slice(index, index + size));
  }
  return chunks;
};

const upsertQuestionBankBatch = async (db, questions) => {
  if (!db || !questions.length) return;
  for (const chunk of chunkArray(questions, 400)) {
    const batch = writeBatch(db);
    chunk.forEach((question) => {
      batch.set(doc(db, 'questionBank', question.id), question, { merge: true });
    });
    await batch.commit();
  }
};

const buildQuestionBankSegmentReplacement = (
  targetBankType = 'game',
  existingQuestions = [],
  replacementQuestions = [],
  usedQuestionIds = new Set(),
) => {
  const normalizedTargetBankType = normalizeQuestionBankType(targetBankType);
  const replacements = dedupeQuestionsById(
    replacementQuestions.filter((question) =>
      question?.id && normalizeQuestionBankType(question?.bankType) === normalizedTargetBankType,
    ),
  ).map(activateQuestionBankRecord);
  const replacementIds = new Set(replacements.map((question) => question.id));
  const staleQuestions = existingQuestions.filter((question) =>
    question?.id
    && normalizeQuestionBankType(question?.bankType) === normalizedTargetBankType
    && !replacementIds.has(question.id),
  );
  const retiredQuestions = staleQuestions
    .filter((question) => isQuestionUsedInHistory(question, usedQuestionIds))
    .map((question) => retireQuestionBankRecordFromSheet(question));
  const deletedQuestions = staleQuestions.filter((question) => !isQuestionUsedInHistory(question, usedQuestionIds));

  return {
    replacements,
    retiredQuestions,
    deletedQuestions,
  };
};

const applyQuestionBankSegmentReplacement = (
  currentQuestions = [],
  targetBankType = 'game',
  replacementQuestions = [],
  usedQuestionIds = new Set(),
) => {
  const { replacements, retiredQuestions, deletedQuestions } = buildQuestionBankSegmentReplacement(
    targetBankType,
    currentQuestions,
    replacementQuestions,
    usedQuestionIds,
  );
  const deletedIds = new Set(deletedQuestions.map((question) => question.id));
  return mergeQuestionBankRecords(
    currentQuestions.filter((question) => !deletedIds.has(question?.id)),
    replacements,
    retiredQuestions,
  );
};

const replaceQuestionBankSegmentBatch = async (
  db,
  targetBankType = 'game',
  existingQuestions = [],
  replacementQuestions = [],
  usedQuestionIds = new Set(),
) => {
  if (!db) return { replaced: 0, removed: 0, retired: 0 };
  const { replacements, retiredQuestions, deletedQuestions } = buildQuestionBankSegmentReplacement(
    targetBankType,
    existingQuestions,
    replacementQuestions,
    usedQuestionIds,
  );

  for (const chunk of chunkArray(replacements, 400)) {
    const batch = writeBatch(db);
    chunk.forEach((question) => {
      batch.set(doc(db, 'questionBank', question.id), question, { merge: true });
    });
    await batch.commit();
  }

  for (const chunk of chunkArray(retiredQuestions, 400)) {
    const batch = writeBatch(db);
    chunk.forEach((question) => {
      batch.set(doc(db, 'questionBank', question.id), question, { merge: true });
    });
    await batch.commit();
  }

  for (const chunk of chunkArray(deletedQuestions, 400)) {
    const batch = writeBatch(db);
    chunk.forEach((question) => {
      batch.delete(doc(db, 'questionBank', question.id));
    });
    await batch.commit();
  }

  return { replaced: replacements.length, removed: deletedQuestions.length, retired: retiredQuestions.length };
};

function Button({ children, className = 'ghost-button compact', ...props }) {
  return (
    <button type="button" className={className} {...props}>
      {children}
    </button>
  );
}

function useMediaQuery(query) {
  const [matches, setMatches] = useState(() => {
    if (typeof window === 'undefined' || !window.matchMedia) return false;
    return window.matchMedia(query).matches;
  });

  useEffect(() => {
    if (typeof window === 'undefined' || !window.matchMedia) return undefined;
    const mediaQuery = window.matchMedia(query);
    const update = () => setMatches(mediaQuery.matches);
    update();
    if (mediaQuery.addEventListener) {
      mediaQuery.addEventListener('change', update);
      return () => mediaQuery.removeEventListener('change', update);
    }
    mediaQuery.addListener(update);
    return () => mediaQuery.removeListener(update);
  }, [query]);

  return matches;
}

function useChatUnreadCount(messages, isOpen, currentUserId = '', resetKey = '') {
  const [unreadCount, setUnreadCount] = useState(0);
  const lastObservedMessageIdRef = useRef('');
  const initializedRef = useRef(false);

  useEffect(() => {
    lastObservedMessageIdRef.current = '';
    initializedRef.current = false;
    setUnreadCount(0);
  }, [resetKey]);

  useEffect(() => {
    const lastMessageId = messages.at(-1)?.id || '';

    if (isOpen) {
      lastObservedMessageIdRef.current = lastMessageId;
      initializedRef.current = true;
      setUnreadCount(0);
      return;
    }

    if (!initializedRef.current) {
      lastObservedMessageIdRef.current = lastMessageId;
      initializedRef.current = true;
      return;
    }

    if (!lastMessageId || lastMessageId === lastObservedMessageIdRef.current) return;

    const previousMessageId = lastObservedMessageIdRef.current;
    const previousMessageIndex = previousMessageId
      ? messages.findIndex((message) => message.id === previousMessageId)
      : -1;
    const newMessages = previousMessageIndex >= 0 ? messages.slice(previousMessageIndex + 1) : messages;
    const incomingCount = newMessages.filter((message) => String(message?.uid || '') !== String(currentUserId || '')).length;

    if (incomingCount > 0) {
      setUnreadCount((current) => current + incomingCount);
    }

    lastObservedMessageIdRef.current = lastMessageId;
  }, [currentUserId, isOpen, messages]);

  return unreadCount;
}

function MobileChatLauncher({
  title = 'Chat',
  isOpen,
  onOpen,
  onClose,
  unreadCount = 0,
  messages,
  draft,
  onDraftChange,
  onSend,
  isBusy,
  seat,
  displayName,
}) {
  useEffect(() => {
    if (!isOpen) return undefined;
    const handleKeyDown = (event) => {
      if (event.key === 'Escape') onClose?.();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, onClose]);

  useEffect(() => {
    if (typeof document === 'undefined') return undefined;
    document.body.classList.toggle('mobile-chat-sheet-open', Boolean(isOpen));
    return () => {
      document.body.classList.remove('mobile-chat-sheet-open');
    };
  }, [isOpen]);

  const unreadLabel = unreadCount > 9 ? '9+' : String(unreadCount);

  const launcherNode = (
    <>
      <button
        type="button"
        className={`mobile-chat-fab ${isOpen ? 'is-open' : ''} ${unreadCount > 0 ? 'has-unread' : ''}`}
        onClick={isOpen ? onClose : onOpen}
        aria-expanded={isOpen}
        aria-haspopup="dialog"
        aria-label={unreadCount > 0 ? `${title}. ${unreadCount} unread messages.` : title}
      >
        <span className="mobile-chat-fab__icon" aria-hidden="true">
          <svg viewBox="0 0 24 24" role="img" aria-hidden="true">
            <path
              d="M5 6.5h14a2 2 0 0 1 2 2v7a2 2 0 0 1-2 2H11l-4.8 3.4c-.5.3-1.2 0-1.2-.6V17.5H5a2 2 0 0 1-2-2v-7a2 2 0 0 1 2-2Z"
              fill="none"
              stroke="currentColor"
              strokeWidth="1.8"
              strokeLinejoin="round"
            />
          </svg>
          {unreadCount > 0 ? <span className="mobile-chat-fab__dot" /> : null}
        </span>
        <span className="mobile-chat-fab__label">Chat</span>
        {unreadCount > 0 ? <span className="mobile-chat-fab__badge">{unreadLabel}</span> : null}
      </button>

      {isOpen ? (
        <div className="mobile-chat-sheet-backdrop" role="presentation" onClick={onClose}>
          <section
            className="panel mobile-chat-sheet"
            role="dialog"
            aria-modal="true"
            aria-label={title}
            onClick={(event) => event.stopPropagation()}
          >
            <div className="mobile-chat-sheet__head">
              <div>
                <p className="eyebrow">Mobile Chat</p>
                <h2>{title}</h2>
              </div>
              <Button className="ghost-button compact" onClick={onClose}>
                Close
              </Button>
            </div>
            <ChatPanel
              compact
              messages={messages}
              draft={draft}
              onDraftChange={onDraftChange}
              onSend={onSend}
              isBusy={isBusy}
              seat={seat}
              displayName={displayName}
            />
          </section>
        </div>
      ) : null}
    </>
  );

  if (typeof document === 'undefined') return launcherNode;
  return createPortal(launcherNode, document.body);
}

