            <path d="m18.5 4 .7 1.8L21 6.5l-1.8.7-.7 1.8-.7-1.8-1.8-.7 1.8-.7.7-1.8ZM6 16.5l.9 2.2L9 19.5l-2.1.8L6 22.5l-.9-2.2L3 19.5l2.1-.8.9-2.2Z" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinejoin="round" />
